<?php namespace App\Domains\Auto\Policies; use Illuminate\Auth\Access\HandlesAuthorization; class VehiclePolicy { use HandlesAuthorization; public function viewAny($user) { return true; } public function view($user, $vehicle) { return $user->tenant_id === $vehicle->tenant_id; } public function create($user) { return true; } public function update($user, $vehicle) { return $user->tenant_id === $vehicle->tenant_id; } public function delete($user, $vehicle) { return $user->tenant_id === $vehicle->tenant_id; } }
